INSERT INTO `hospitals` VALUES (5,3,'','',38.14398663,39.47550299,'','','2026-03-11 08:51:00',NULL,NULL),(6,5,'','Diyarbakır’ın Çüngüş Devlet Hastanesi, ilçenin coğrafi yapısı ve ulaşım şartları göz önüne alındığında kritik bir öneme sahip olan, butik ama modern bir sağlık kuruluşudur. 2026 yılı itibarıyla güncel bilgiler şöyledir:\r\n\r\n🏥 Genel Kapasite ve Bina Özellikleri\r\nYatak Kapasitesi: 10 yataklı bir ilçe hastanesidir (Entegre sağlık hizmeti sunar).\r\n\r\nModernizasyon: Hastane, deprem güvenliği ve modern sağlık standartlarına uygun olarak yenilenmiş bir binada hizmet vermektedir.\r\n\r\nHizmet Yapısı: \"E-Grubu\" entegre ilçe hastanesi kategorisindedir; yani hem hastane hizmetlerini hem de toplum sağlığı merkezi görevlerini bir arada yürütür.\r\n\r\n🩺 Sunulan Sağlık Hizmetleri\r\nİlçe nüfusuna yönelik temel sağlık ihtiyaçlarını karşılamak üzere şu birimler aktiftir:\r\n\r\nAcil Servis: 7/24 kesintisiz hizmet veren acil tıp birimi.\r\n\r\nPoliklinikler: Aile Hekimliği uzmanları ve belirli günlerde görev yapan rotasyonel (geçici görevli) uzman doktorlar ile hizmet verilir. Genellikle Dahiliye ve Çocuk Sağlığı branşlarında düzenli muayene imkanı sunulur.\r\n\r\nAğız ve Diş Sağlığı: Diş polikliniği birimi aktif olarak hizmet vermektedir.\r\n\r\nLaboratuvar ve Görüntüleme: Temel kan/idrar tahlilleri ve röntgen hizmetleri hastane bünyesinde mevcuttur.\r\n\r\n🚑 Sevk ve Ulaşım\r\nÇüngüş’ün Diyarbakır il merkezine uzak olması (yaklaşık 120 km) nedeniyle, hastane stabilizasyon merkezi görevi görür.\r\n\r\nAmeliyat gerektiren veya ileri tetkik isteyen vakalar için tam donanımlı ambulanslar ile genellikle Diyarbakır Gazi Yaşargil Eğitim ve Araştırma Hastanesi\'ne sevk sağlanır.\r\n\r\n📞 İletişim Bilgileri\r\nAdres: Karşıyaka Mahallesi, Çüngüş / Diyarbakır.\r\n\r\nTelefon: +90 (412) 541 20 11\r\n\r\nRandevu: MHRS (182) sistemi üzerinden veya doğrudan başvurarak randevu alınabilir.',38.21336124,39.29497901,'','','2026-03-11 10:42:40',NULL,NULL);
/*!40000 ALTER TABLE `hospitals` ENABLE KEYS */;
UNLOCK TABLES;

