INSERT INTO `road_stops` VALUES (8,14,'Kaya Sil├╝etleri Ba┼şlang─▒c─▒',150,'Sa─ş taraf─▒n─▒zdaki kayalara bak─▒n, sanki bir insan dizisi gibi duruyorlar de─şil mi? Efsaneye g├Âre buras─▒ bir gelin alay─▒d─▒r.'),(9,14,'Zirve Manzara Noktas─▒',100,'Harika bir manzara! Buradan t├╝m ├çermik ayaklar─▒n─▒z─▒n alt─▒nda. Derinden bir nefes al─▒n.'),(10,15,'Vadi Giri┼şi',200,'Kanyona girmek ├╝zeresiniz. Havan─▒n serinledi─şini hissetmeye ba┼şlayacaks─▒n─▒z.'),(11,15,'Ana ┼Şelale G├Âr├╝┼ş Alan─▒',50,'─░┼şte o muazzam ses! ┼Şeyhandede ┼Şelalesi t├╝m ihti┼şam─▒ ile kar┼ş─▒n─▒zda.'),(12,16,'Tarihi Sinek K├Âpr├╝s├╝',100,'Bu eski k├Âpr├╝, Sinek ├çay─▒\'n─▒n en karakteristik yap─▒lar─▒ndan biridir. Foto─şraf ├ğekmek i├ğin durabilirsiniz.'),(13,16,'┼Şelale Yan─▒ Piknik Alan─▒',100,'Burada bir mola verip Sinek ├çay─▒\'n─▒n buz gibi suyunda karpuz ├ğatlatmaya ne dersiniz?'),(14,17,'Antik Basamaklar',50,'Binlerce y─▒l ├Ânce buradan kervanlar─▒n ge├ğti─şini hayal edin. Bu ta┼ş basamaklar o g├╝nlerden kalma.'),(15,17,'Ticaret Yolu Kav┼şa─ş─▒',100,'Buras─▒ do─şu ile bat─▒y─▒ ba─şlayan ana damarlardan biriydi.'),(16,18,'G├Âzeler Mevkii',100,'Suyun yeralt─▒ndan kaynad─▒─ş─▒ noktaya ├ğok yakla┼şt─▒n─▒z. Su burada en saf halindedir.'),(17,18,'Ma─şaralar B├Âlgesi',150,'Solunuzdaki yama├ğlarda ke┼şfedilmeyi bekleyen bir├ğok gizemli ma─şara bulunuyor.');
