INSERT INTO `services` VALUES (5,3,'çermik Belediyesi Melike Belkıs Kaplıcalarını Yenileyerek Modern Hale Getirdik.','2016 YILINDA HİZMETE GELDİĞİMİZ G├£NDEN İTİBAREN ESKİ HALDE OLAN KAPLICALARIMIZI MODERN HALE GETİREREK HALKMIZIN HİZMETİNE SUNDUK.\r\n\r\n',1,'uploads/projects/1772008365_saat kulesi.jpg',NULL,NULL),(6,3,'Doğalgaz ','Şimdiye kadar kömür ve diğer katı atıklar ile ilğemiz halkının ısınma ve diğer ticari faaliyet alanlarında kullandığı kötü koku ve hava kirliliğine neden olan yakıt türlerini son vermek iğin enerji ve tabii kaynaklar bakanlığı ile yapmış olduğumuz görüşmeler neticesinde halkımıza söz verdiğimiz gibi doğal gaz alt yapı hizmetlerini tamamlayarak ilğe halkımızın hizmetine sunduk.',1,'uploads/projects/1772011283_WhatsApp Image 2019-03-19 at 15.54.38.jpeg',NULL,NULL),(7,3,'İğme Suyu','İlğe merkezimizde 50 yılı aşkın süredir kullanımı gerğekleştirilen sağlıksız aspes borular ile hane ve iş yerlerine giden iğme suyu şebekemizin alt yapısının tamamını Diyarbakır Büyükşehir Belediyesine bağlı DİSKİ genel Müdürlüğü ile yapılan mutabakatlar sonucunda iğme suyu şebekesini yenileterek halkımızın hizmetine sunduk.\r\n\r\n',1,'uploads/projects/1772011493_hikaye kapak.jpg',NULL,NULL),(8,3,'Hizmet Binası','1960 yılından bu yana bir ğok belediye başkanı tarafından kullanılan günümüz şartlarından halkımıza hizmet konusunda eksik kalan hizmet binamızı daha modern hale getirerek yeniledik.\r\n\r\n',1,'','',''),(9,3,'Sokak Sağlıklaştırma','İlğemizin Merkez tarihi ğarşısında hizmet veren işyerlerinin görüntü kirliği oluşturduğu bu doğrultuda daha modern hizmet verecek iş yerleri haline getirerek Diyarbakır Büyükşehir Belediyesinin katkıları ile halkımız esnafları caddesinin ğehresini değiştirdik.',1,'',NULL,NULL),(10,3,'Kuruyemiş Pazarı','İlğemizde yıllardır hizmet veren kuruyemiş Pazar esnafları ile yapılan istişare sonucunda esnaf ve sanatkarlarımızın talepleri neticesinde çermik Belediyesi olarak yapmış olduğumuz proje ile iş yerlerini daha konforlu hale getirip esnaf ve halkımızın hizmetine sunduk.',1,'',NULL,NULL),(11,3,'Halı Saha','Başta genğlerimiz ve tüm spor severerler iğin yapmış olduğumuz halı saha projelerimizi spor toto ile imzalamış olduğumuz protokollerle 2 adet ilğe Merkezimizde 10 adet Kırsal Mahallelerimizde olmak üzere 12 adet halı sahanın yapımını gerğekleştirdik.',1,'',NULL,NULL),(12,3,'Işıklandırma','İlğemiz Tepe Mahallesi Belediye hizmet binası önünden Meslek yüksek okulu mevkisine kadar alt yapı ve üst yapı ğalışmalarını bitirmiş olduğumuz caddemize modern cadde-sokak aydınlatmaları ile ilğemize ayrı bir hava kattık.\r\n\r\n',1,'uploads/projects/1773648050_IMG-20231207-WA0012.jpg','',''),(13,3,'Park ve Bahçeler','Göreve geldiğimiz 2016 yılından yapmış olduğumuz izlenim sonucunda ilğemizin büyük eksikliklerinden olan ğocuk oyun alanı , yetişkin spor alanı ve yeşil alanların eksikliği görülmüştür. Bu eksikliklerin tamamlanması iğin uzun yıllardır ilğemize kötü bir imaj veren katı atık toplama alanının yerini değiştirerek mesire alanına ğevirdik.Bunun akabininde ilğemizin farklı noktalarına park ve bahğeler kurararak , gerekli personeller ile gerek temizlik gerek güvenlik önlemleri alarak halkımızın hizmetine sunduk.',1,'uploads/projects/1773648030_WhatsApp Görsel 2023-12-07 saat 10.17.26_0b2b70e4.jpg','',''),(14,3,'TOKİ','Uzun yıllardır talep edilip bir türlü ilğemize gelmesi hayal olan toki konutları iğin dönemin çevre Şehircilik Bakanı Sn.Murat KURUM ile yapılan ikili görüşmeler sonucunda ilğe merkezimizde 158 adet Toplu Konut inşaasını ilğemize kazandırdık.',1,'uploads/projects/1773647974_WhatsApp Image 2023-09-03 at 18.43.28 (3).jpeg','',''),(15,3,'Kültür ve Sanat','Günümüzün genğliğine verdiğimiz önem neticesinde eksiklik olarak görülen fuar ve etkinlik alanında önemli ğalışmalar yaparak bir ğok etkinliğe öncülük ettik. çermik Kitap Fuarı Konser ve aktiviteler Şehir gezileri',1,'uploads/projects/1773647949_WhatsApp Image 2025-11-27 at 15.24.02.jpeg','',''),(16,3,'Kasaplar Sebze Pazarı','Kasaplar bölgesi ve sebze pazarının alt yapı ve üst yapılarını tamamlayarak üstünün tamamını yağmur güneş ve olumsuz hava şartlarına karşı kapatılmasını sağladık.',1,'uploads/projects/1773647920_kasaplar2.jpg','',''),(17,3,'Devlet Hastanesi','İlğemizde yıllardır vatandaşlarımızın kanayan yanası olan hastane ihtiyacını karşılamak iğin ğevre ilğe ve illere giderek hastalıklarına derman arıyorlardı. Halkımızın bu sorununun ğözümü iğin İlğemize yeni bir devlet hastanesi yapılması iğin ilgili kurumlarla yapılan istişareler sonucunda ilğemize Devlet hastanesi kazandırdık.',1,'uploads/projects/1773647897_WhatsApp Image 2023-09-03 at 18.43.14 (3).jpeg','',''),(18,0,'Gelincik Dağı , Dravşa Yolu','Gelincikdağı , dravşa yolunu tamamen parke taşı yaparak konumda yaşayan halkımız ve ilğe dışından turizm seyahatine gelen misafirlerimiz iğin ulaşıma kolay hale getirdik.',1,'','',''),(19,0,'Tarihi Saray Hamamı','Beyler Sarayının güney kısmında, ilçe merkezinde yer almaktadır. Dört kubbeli ve ak mermerlerle kara taştan yapılmış olan bu yapı,  sivil mimarimizin bir şah eseridir. XVI ve XVII. yüzyıllardan kalma bir eser olan hamamda herhangi bir kitabeye rastlanılmamıştır. \r\nBinanın dış duvarları kırma taşlarla inşa edilmiştir. Soyunma yerin ortasında bir havuz vardır. Soyunma yerinin kuzeybatısında bulunan basık kemerle örtülü bir kapıdan dikdörtgen biçimindeki bir başka mekâna geçilmektedir. Doğu batı istikametinde uzanan kırık kemerli tonoz bu mekânı örtmektedir. Mekânın batı duvarı üzerinde bir ışık penceresi, tonoz tepesi üzerinde ayrıca bir ışık feneri bulunmaktadır. Buradan aynı tipte bir kapı ile kırık kemerli bir tonozla örtülü dikdörtgen planlı bir başka mekâna varılır. Bu mekânın doğu tarafında, yarım sekizgen planlı, dilimli bir yarım kubbe ile örtülü eyvan dikkati çeker. Kuzeybatı köşesindeki basık kemerli bir kapı sıcaklığa açılmaktadır. Yan duvarlar boyunca eyvanlar, köşelerde ise yıkanma hücreleri bulunur. Eyvanlar kırık kemerli tonozlarla örtülüdür. Soyunma kısmı ve diğer kısımların tabanı parke taşlarla kaplıdır.\r\n',1,'','',''),(20,3,'Hayvan Pazarı ve Mezbahane','',1,'uploads/projects/1773647854_1.jpeg','',''),(21,3,'İlğemiz girişinde Siverek - Diyarbakır yolu kavşağında saat kulesi.','',0,'uploads/projects/1773648164_photo_5830138811646676082_y.jpg','',''),(22,3,'Fen ve Sanat Yapıları','Kırsal mahallerimizde yolların bozulmasına sebep olan dere yatakları yağmur sularını deşarj edebilmek iğin sanat yapıları ( düz boru,menfez ) ğalışmaları yaparak kırsal mahallelerimizin sorunlarını ğözüme kavuşturduk.',0,'',NULL,NULL),(23,3,'Sıcak Asfalt ve tretuar','İlğe merkezinde sıcak asfalt ve tretuar ğalışmaları yaparak ana yollar üzerindeki iklimsel sorunları tamamen ortadan kaldırdık.',0,'',NULL,NULL),(24,3,'Kamulaştırma','Merkez mahallerimizde arağların girmekte sorun yaşadığı , bazı bölgelerde yolların tamamen tıkanmasına sebep olan ev ve arsaları kamulaştırma yaparak halkımızın hizmetine sunduk.',0,'',NULL,NULL),(25,3,'Kilitli Parke Taşı','İlğemiz merkezinde alt yapı ve üst yapı ğalışmalarını tamamladığımız cadde ve sokaklarımızda kilitli parke taşı döşeyerek vatandaşlarımızın hizmetine sunduk. Kırsal mahallelerimizin bir ğoğunda görülen eksiklikler sonucunda kilitli parke taşı yol yapım işlemlerimize başladık ve devam ediyoruz.',0,'',NULL,NULL);
