INSERT INTO `settings` VALUES (1,0,'mayor_name','Suat AKMEŞE','2026-03-18 08:42:37','FREEMIND','7073c30918869aee144ddca9','bb37df2be980e603326bce12'),(2,0,'mayor_title','Çüngüş Belediye Başkanı','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(3,0,'mayor_image','assets/img/baskan.png','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(4,0,'site_name','Çermik Belediyesi','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(5,0,'site_email','admin@cermil.bel.tr','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(6,0,'site_phone','4124612001','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(7,0,'site_address','Tepe Mah.','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(8,0,'copyright_text','Rotamız Çermik','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(9,0,'facebook_link','https://www.facebook.com/p/%C3%87ermik-Belediyesi-100064935810446/?locale=tr_TR','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(10,0,'instagram_link','https://www.instagram.com/cermikbelediyesi/','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(11,0,'youtube_link','https://www.youtube.com/@cermikbelediyesi','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(12,0,'twitter_link','https://x.com/cermikbld/status/1923747974338748880','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(13,0,'kvkk_text','1. İşlenen Kişisel Verileriniz\r\nUygulamayı kullanımınız sırasında aşağıdaki verileriniz işlenebilir:\r\n\r\nKimlik Bilgileri: Ad, soyadı.\r\nİletişim Bilgileri: E-posta adresi, telefon numarası.\r\nKonum Bilgileri: Cihazınızın GPS verileri (yakınındaki tarihi yerleri göstermek ve bildirim göndermek amacıyla).\r\nİşlem Güvenliği: IP adresi, uygulama giriş-çıkış kayıtları, cihaz modeli.\r\n\r\n2. Kişisel Verilerin İşlenme Amaçları\r\nKişisel verileriniz, RotaRehber\'in tanıtımı ve belediye hizmetlerinin iyileştirilmesi amacıyla şu durumlarda işlenir:\r\n- Uygulama içerisinde kullanıcı hesabı oluşturulması.\r\n- Yerel Rehber hizmeti kapsamında konumunuza yakın tarihi ve turistik yerlerin gösterilmesi.\r\n- Belediye duyuruları, etkinlikler ve turistik bilgilendirmeler hakkında bildirim gönderilmesi.\r\n- Uygulama performansının ölçülmesi ve kullanıcı deneyiminin geliştirilmesi.\r\n\r\n3. Kişisel Verilerin Aktarılması\r\nKişisel verileriniz, yasal yükümlülüklerin yerine getirilmesi amacıyla yetkili kamu kurum ve kuruluşları ile paylaşılabilecek olup; bunun dışında üçüncü taraflarla ticari amaçla paylaşılmamaktadır.\r\n\r\n4. Kişisel Veri Toplamanın Yöntemi ve Hukuki Sebebi\r\nVerileriniz, uygulamayı telefonunuza indirmeniz, kayıt formunu doldurmanız ve uygulama izinlerini (Konum, Bildirim vb.) onaylamanız suretiyle tamamen dijital ortamda toplanmaktadır. İşleme faaliyeti, KVKK’nın 5. maddesinde yer alan \"İlgili kişinin açık rızası\" ve \"Veri sorumlusunun hukuki yükümlülüğü\" sebeplerine dayanır.\r\n\r\n5. Veri Sahiplerinin Hakları\r\nKVKK’nın 11. maddesi uyarınca veri sorumlusuna başvurarak; verilerinizin işlenip işlenmediğini öğrenme, bilgi talep etme, eksik veya yanlış işlenmişse düzeltilmesini isteme, silinmesini veya yok edilmesini isteme haklarına sahipsiniz.','2026-03-19 07:48:20','FREEMIND',NULL,NULL),(14,0,'cookie_policy','RotaRehber Çerez (Cookie) Politikası\r\n\r\n1. Çerez Nedir?\r\nÇerezler, bir internet sitesini ziyaret ettiğinizde cihazınıza (bilgisayar, telefon, tablet) kaydedilen küçük metin dosyalarıdır. Bu dosyalar, sitenin sizi tanımasını, tercihlerini hatırlamasını ve size daha iyi bir deneyim sunulmasını sağlar.\r\n\r\n2. Hangi Tür Çerezleri Kullanıyoruz?\r\nPlatformumuzda aşağıdaki çerez türleri kullanılmaktadır:\r\n- Zorunlu Çerezler: Sitenin çalışması için temel fonksiyonlardır (Örn: Güvenli giriş yapma, oturum yönetimi).\r\n- Performans ve Analiz Çerezleri: Ziyaretçi sayısını ve trafiği anlamamıza yardımcı olur.\r\n- İşlevsel Çerezler: Dil seçimi, konum tercihi gibi kişiselleştirme amaçlıdır.\r\n- Hedefleme ve Reklam Çerezleri: İlginizi çekebilecek yerel işletmelerin veya içeriklerin sunulması için kullanılır.\r\n\r\n3. Çerezleri Neden Kullanıyoruz?\r\nRotaRehber olarak çerezleri şunlar için kullanıyoruz: Kullanıcı deneyimini iyileştirmek, size en yakın konumları sunmak, kimlik doğrulama sistemlerimizin güvenliğini sağlamak ve site performansını analiz etmek.\r\n\r\n4. Üçüncü Taraf Çerezleri\r\nSitemizde Google Haritalar gibi üçüncü taraf servisler kullanılabilir. Bu servisler kendi çerez politikalarına sahip olabilirler.\r\n\r\n5. Çerezleri Nasıl Kontrol Edebilirsiniz?\r\nTarayıcınızın ayarlar kısmından çerezleri engelleyebilir veya silebilirsiniz. Ancak zorunlu çerezlerin kapatılması durumunda sitenin bazı özellikleri (Örn: Giriş yapma) düzgün çalışmayabilir.\r\n\r\n6. İletişim\r\nSorularınız için admin@rotarehber.com üzerinden bizimle iletişime geçebilirsiniz.','2026-03-19 07:48:20','FREEMIND',NULL,NULL),(86,0,'explore_desc','Tarihin Sıcaklığı, Doğanın Saklı Yüzü','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(87,0,'explore_desc_en','The Warmth of History, The Hidden Face of Nature','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(113,0,'last_pharmacy_fetch','1773136490','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(116,0,'admin_password_hash','$2y$12$j.OuaXZjOuA9ISS.rh80B.dpmgWOPT4xQG/dluDDKtOvGgnYugaku','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(117,0,'admin_username','admin','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(119,0,'mayor_title_en','Mayor of \\u00c7ermik','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(133,0,'sms_username','7073c30918869aee144ddca9','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(134,0,'sms_password','bb37df2be980e603326bce12','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(135,0,'sms_title','FREEMIND','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(136,0,'otp_enabled','0','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(139,0,'menu_parks_tr','Parklar','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(140,0,'menu_parks_en','Parks and Gardens','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(141,3,'site_name','Çermik ','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(142,3,'site_email','biltektasarim@gmail.com','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(143,3,'site_phone','4124612001','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(144,3,'site_address','sass','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(145,3,'copyright_text','Rotamız Çermik','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(146,3,'explore_desc','','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(147,3,'explore_desc_en','','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(148,3,'facebook_link','https://www.facebook.com/p/%C3%87ermik-Belediyesi-100064935810446/?locale=tr_TR','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(149,3,'instagram_link','https://www.instagram.com/cermikbelediyesi/','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(150,3,'youtube_link','https://www.youtube.com/@cermikbelediyesi','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(151,3,'twitter_link','https://x.com/cermikbld/status/1923747974338748880','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(152,3,'kvkk_text','1. İşlenen Kişisel Verileriniz\r\nUygulamayı kullanımınız sırasında aşağıdaki verileriniz işlenebilir:\r\n\r\nKimlik Bilgileri: Ad, soyadı.\r\nİletişim Bilgileri: E-posta adresi, telefon numarası.\r\nKonum Bilgileri: Cihazınızın GPS verileri (yakınındaki tarihi yerleri göstermek ve bildirim göndermek amacıyla).\r\nİşlem Güvenliği: IP adresi, uygulama giriş-çıkış kayıtları, cihaz modeli.\r\n\r\n2. Kişisel Verilerin İşlenme Amaçları\r\nKişisel verileriniz, RotaRehber\'in tanıtımı ve belediye hizmetlerinin iyileştirilmesi amacıyla şu durumlarda işlenir:\r\n- Uygulama içerisinde kullanıcı hesabı oluşturulması.\r\n- Yerel Rehber hizmeti kapsamında konumunuza yakın tarihi ve turistik yerlerin gösterilmesi.\r\n- Belediye duyuruları, etkinlikler ve turistik bilgilendirmeler hakkında bildirim gönderilmesi.\r\n- Uygulama performansının ölçülmesi ve kullanıcı deneyiminin geliştirilmesi.\r\n\r\n3. Kişisel Verilerin Aktarılması\r\nKişisel verileriniz, yasal yükümlülüklerin yerine getirilmesi amacıyla yetkili kamu kurum ve kuruluşları ile paylaşılabilecek olup; bunun dışında üçüncü taraflarla ticari amaçla paylaşılmamaktadır.\r\n\r\n4. Kişisel Veri Toplamanın Yöntemi ve Hukuki Sebebi\r\nVerileriniz, uygulamayı telefonunuza indirmeniz, kayıt formunu doldurmanız ve uygulama izinlerini (Konum, Bildirim vb.) onaylamanız suretiyle tamamen dijital ortamda toplanmaktadır. İşleme faaliyeti, KVKK’nın 5. maddesinde yer alan \"İlgili kişinin açık rızası\" ve \"Veri sorumlusunun hukuki yükümlülüğü\" sebeplerine dayanır.\r\n\r\n5. Veri Sahiplerinin Hakları\r\nKVKK’nın 11. maddesi uyarınca veri sorumlusuna başvurarak; verilerinizin işlenip işlenmediğini öğrenme, bilgi talep etme, eksik veya yanlış işlenmişse düzeltilmesini isteme, silinmesini veya yok edilmesini isteme haklarına sahipsiniz.','2026-03-19 07:48:20','FREEMIND',NULL,NULL),(153,3,'cookie_policy','RotaRehber Çerez (Cookie) Politikası\r\n\r\n1. Çerez Nedir?\r\nÇerezler, bir internet sitesini ziyaret ettiğinizde cihazınıza (bilgisayar, telefon, tablet) kaydedilen küçük metin dosyalarıdır. Bu dosyalar, sitenin sizi tanımasını, tercihlerini hatırlamasını ve size daha iyi bir deneyim sunulmasını sağlar.\r\n\r\n2. Hangi Tür Çerezleri Kullanıyoruz?\r\nPlatformumuzda aşağıdaki çerez türleri kullanılmaktadır:\r\n- Zorunlu Çerezler: Sitenin çalışması için temel fonksiyonlardır (Örn: Güvenli giriş yapma, oturum yönetimi).\r\n- Performans ve Analiz Çerezleri: Ziyaretçi sayısını ve trafiği anlamamıza yardımcı olur.\r\n- İşlevsel Çerezler: Dil seçimi, konum tercihi gibi kişiselleştirme amaçlıdır.\r\n- Hedefleme ve Reklam Çerezleri: İlginizi çekebilecek yerel işletmelerin veya içeriklerin sunulması için kullanılır.\r\n\r\n3. Çerezleri Neden Kullanıyoruz?\r\nRotaRehber olarak çerezleri şunlar için kullanıyoruz: Kullanıcı deneyimini iyileştirmek, size en yakın konumları sunmak, kimlik doğrulama sistemlerimizin güvenliğini sağlamak ve site performansını analiz etmek.\r\n\r\n4. Üçüncü Taraf Çerezleri\r\nSitemizde Google Haritalar gibi üçüncü taraf servisler kullanılabilir. Bu servisler kendi çerez politikalarına sahip olabilirler.\r\n\r\n5. Çerezleri Nasıl Kontrol Edebilirsiniz?\r\nTarayıcınızın ayarlar kısmından çerezleri engelleyebilir veya silebilirsiniz. Ancak zorunlu çerezlerin kapatılması durumunda sitenin bazı özellikleri (Örn: Giriş yapma) düzgün çalışmayabilir.\r\n\r\n6. İletişim\r\nSorularınız için admin@rotarehber.com üzerinden bizimle iletişime geçebilirsiniz.','2026-03-19 07:48:20','FREEMIND',NULL,NULL),(154,3,'sms_username','7073c30918869aee144ddca9','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(155,3,'sms_password','bb37df2be980e603326bce12','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(156,3,'sms_title','FREEMIND','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(157,3,'otp_enabled','0','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(160,5,'menu_historical_tr','Tarihi Mekanlar','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(161,5,'menu_historical_en','Historical Places','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(164,0,'last_pharmacy_fetch_3','1774108494','2026-03-21 15:54:54','FREEMIND',NULL,NULL),(165,3,'menu_parks_tr','Parklar ve Bahçeler','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(166,3,'menu_parks_en','Parks and Gardens','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(168,0,'menu_hospital_tr','Hastane & Eczane','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(169,0,'menu_hospital_en','Hospital & Pharmacy','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(174,5,'site_name','Çüngüş Belediyesi','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(175,5,'site_email','','2026-03-16 07:23:49','FREEMIND',NULL,NULL),(176,5,'site_phone','4124612001','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(177,5,'site_address','Tepe Mah.','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(178,5,'copyright_text','Rotamız Çüngüş','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(179,5,'explore_desc','Tarihin Sıcaklığı, Doğanın Saklı Yüzü','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(180,5,'explore_desc_en','The Warmth of History, The Hidden Face of Nature','2026-03-11 20:36:26','FREEMIND',NULL,NULL),(181,5,'facebook_link','https://www.facebook.com/p